import React from 'react';

function NotificationsPanel({ visible, onHide }) {
  if (!visible) return null;

  return (
    <>
      {/* Overlay для закрытия при клике вне панели */}
      <div 
        style={{
          position: 'fixed',
          top: 0,
          left: 0,
          right: 0,
          bottom: 0,
          zIndex: 999
        }}
        onClick={onHide}
      />
      
      {/* Панель уведомлений */}
      <div
        style={{
          position: 'fixed',
          top: '80px',
          right: '210px',
          width: '406px',
          height: '336px',
          background: '#FFFFFF',
          borderRadius: '14px',
          boxShadow: '0 4px 12px rgba(0,0,0,0.15)',
          zIndex: 1000,
          display: 'flex',
          flexDirection: 'column'
        }}
        onClick={(e) => e.stopPropagation()}
      >
        {/* Заголовок */}
        <div style={{
          padding: '1.5rem',
          borderBottom: 'none',
          display: 'flex',
          justifyContent: 'space-between',
          alignItems: 'center'
        }}>
          <h3 style={{
            fontSize: '20px',
            fontWeight: '600',
            color: '#1e293b',
            margin: 0
          }}>
            Уведомления
          </h3>
          <button
            onClick={onHide}
            style={{
              background: 'transparent',
              border: 'none',
              cursor: 'pointer',
              padding: '4px',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              color: '#64748b'
            }}
          >
            <i className="pi pi-times" style={{ fontSize: '18px' }}></i>
          </button>
        </div>

        {/* Контент */}
        <div style={{
          padding: '0 1.5rem 1.5rem 1.5rem',
          paddingTop: '0.5rem',
          display: 'flex',
          flexDirection: 'column',
          alignItems: 'flex-start',
          justifyContent: 'flex-start',
          flex: 1,
          position: 'relative',
          overflow: 'hidden'
        }}>
          <div style={{ 
            display: 'flex', 
            flexDirection: 'column',
            gap: '4px',
            width: '100%',
            position: 'relative',
            zIndex: 2
          }}>
            <p style={{ 
              fontSize: '14px', 
              fontWeight: '600', 
              color: '#000000',
              margin: 0,
              lineHeight: '0.3'
            }}>
              Список уведомлений пуст...
            </p>
            <p style={{ 
              fontSize: '14px', 
              fontWeight: '400', 
              color: '#94a3b8',
              margin: 0,
              lineHeight: '1.3'
            }}>
              загляните позже, вдруг что-нибудь появится
            </p>
          </div>

          {/* Герой */}
          <img 
            src="/images/monstr.svg" 
            alt="Персонаж" 
            style={{
              position: 'absolute',
              bottom: '-10px',
              right: '-10px',
              width: '240px',
              height: 'auto',
              zIndex: 1
            }}
          />
        </div>
      </div>
    </>
  );
}

export default NotificationsPanel;
